jsLib:
// 当前书源版本号，切勿修改，否则影响更新的识别
let localVersion = '26.5.29';

// 初始服务器列表
let hosts = [
    'https://v1.gyks.cf',
    'https://v2.gyks.cf',
    'https://v3.gyks.cf',
    'https://v4.gyks.cf',
    'https://v5.gyks.cf',
    'https://v6.gyks.cf',
    'https://v7.gyks.cf',
    'http://101.35.133.34:8888'
];


// 初始化值
const defaultConfig = {
    线路: hosts[0],
    发现页来源: "番茄",
    发现页类型: "小说"
};

// 获取云端配置
function getCloudSettings(r) {
    if (r == undefined) r = false;
    const {
        java,
        cache
    } = this;
    let c = cache.get('gyksconfig');
    if (r || !c) {
        java.longToast(`\n正在更新最新配置`);
        try {
            let url = `${this.BaseUrl()}/static/js/expore.json`;
            //	java.longToast(url)
            let js = java.ajax(url);
            js = JSON.parse(String(js));
            let intc = parseInt(c);
            let intv = parseInt(js['version']);
            if (intc >= intv) {
            	    java.longToast(`\n已是最新配置：${js['version']}`);
            	    return;
            	} else if (!intc && intv) {
            		java.longToast(`\n已初始化配置：${intv}`);
            		} else if (intc < intv || !intc && intv) {
            java.longToast(`\n已更新配置：${intc}→${intv}`);
            } else {
            java.longToast(`\n获取配置失败：请切换线路再试试~`);
            return;
            }
            cache.put('gyksconfig', js['version'])
            this.setVariable('云端配置', js);

            return js;
        } catch (e) {
            java.longToast(`\n获取最新配置失败：${e}`);
        }
    }
}

// 统一获取和解析变量
function _getParsedVariable() {
    const {
        source
    } = this;
    let v = source.getVariable();
    try {
        return JSON.parse(v);
    } catch {
        return defaultConfig;
    }
}

// 获取设置变量
function getLoginInfo(k) {
    const {
        source,
        java
    } = this;
    let res = source.getLoginInfoMap();
    if (!res) {
        res = defaultConfig;
    }
    if (res[k] == '❌') {
        return '0';
    } else if (res[k] == '✅') {
        return '1';
    }
    return res[k]
}

// 还原
function deleteVariable() {
    const {
        source,
        java,
        cache
    } = this;
    source.setVariable('');
    cache.delete('gyksconfig');
    java.longToast('\n所有设置已还原到初始化导入状态');
}

// 获取源变量
function getVariable(k) {
    if (k == undefined) k = "";
    const parsed = this._getParsedVariable();
    if (k == "") {
        return parsed;
    }
    let value = parsed[k];
    if (value == undefined) {
        value = defaultConfig[k];
    }
    return value != undefined ? value : "";
}

// 设置源变量
function setVariable(k, v, t) {
    if (t == undefined) t = true;
    const {
        source,
        java
    } = this;
    const vs = this.getVariable();
    vs[k] = v;
    source.setVariable(JSON.stringify(vs, null, 4));
    if (k != '云端配置' && t) {
        java.toast(`\n设置 ${k} 为 ${v}`)
    }
}

// 获取正在使用的线路
function BaseUrl() {
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    let h = this.getVariable("线路");
    if (!h || String(h) == "undefind") {
        h = hostsbk[0]
    }
    return h;
}

// 切换线路
function switchToNextLine(toast) {
    if (toast == undefined) toast = false;
    const currentLine = this.BaseUrl();
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    let currentIndex = hostsbk.findIndex(item => item == currentLine);
    let nextIndex = (currentIndex + 1) % hostsbk.length;
    const nextLine = hostsbk[nextIndex];
    this.setVariable("线路", nextLine);
    if (toast) {
        this.java.longToast(`\n线路报错，自动切换到:${nextLine}`)
    }
    return nextLine;
}


// 备用设置方案
function ste(v) {
    const {
        java
    } = this;
    let moreSettings = this.getVariable("更多设置") || {};
    let paraSettings = this.getVariable("段评设置") || {};
    if (v=="段评"){
        if (paraSettings["段评开关"] != "false"){
            paraSettings["段评开关"]= "false";
            java.longToast("\n❌段评已关闭");
        }else{
            paraSettings["段评开关"]= "true";
            java.longToast("\n✅段评已开启");
        }
    }
    if (v=="小说" || v=="听书" || v=="漫画" || v=="短剧"){
        moreSettings["搜索模式"]=v;
        java.longToast(`\n已设置搜索模式为 ${v}`);
    }
    if (v=="图片"){
        if (moreSettings["显示图片"] != "false"){
            moreSettings["显示图片"]= "false";
            java.longToast("\n❌已关闭图片显示");
        }else{
            moreSettings["显示图片"]= "true";
            java.longToast("\n✅已开启图片显示");
        }
    }
    if (v=="简介"){
        if (moreSettings["完整简介"] != "false"){
            moreSettings["完整简介"]= "false";
            java.longToast("\n❌已关闭完整简介");
        }else{
            moreSettings["完整简介"]= "true";
            java.longToast("\n✅已开启完整简介");
        }
    }
    if (v=="同步"){
        if (moreSettings["同步书架"] != "false"){
            moreSettings["同步书架"]= "false";
            java.longToast("\n❌已关闭同步书架");
        }else{
            moreSettings["同步书架"]= "true";
            java.longToast("\n✅已开启同步书架");
        }
    }
    if (v=="强制"){
        if (moreSettings["强制搜索"] != "false"){
            moreSettings["强制搜索"]= "false";
            java.longToast("\n❌已关闭强制搜索");
        }else{
            moreSettings["强制搜索"]= "true";
            java.longToast("\n✅已开启强制搜索");
        }
    }
    if (v=="目录"){
        if (moreSettings["目录显示来源"] != "false"){
            moreSettings["目录显示来源"]= "false";
            java.longToast("\n❌已关闭目录显示来源");
        }else{
            moreSettings["目录显示来源"]= "true";
            java.longToast("\n✅已开启目录显示来源");
        }
    }
    if (v=="网络"){
        if (moreSettings["网络模式"] != "服务器"){
            moreSettings["网络模式"]= "服务器";
            java.longToast("\n已切换为 服务器 模式");
        }else{
            moreSettings["网络模式"]= "本地";
            java.longToast("\n已切换为 本地 模式");
        }
    }
    this.setVariable("更多设置", moreSettings, false);
    this.setVariable("段评设置", paraSettings, false);
}

function parseBadMap(str) {
    str = str
        .replace(/^{|}$/g, '');

    const result = {};

    str.split(',').forEach(item => {
        const parts = item.split('=');

        if (parts.length === 2) {
            const key = parts[0].trim();
            const value = parts[1].trim();

            result[key] = value;
        }
    });

    return result;
}

function findItemIndex(data, item_id) {
    if (!data || !Array.isArray(data)) {
        return 0;
    }
    for (let i = 0; i < data.length; i++) {
        if (data[i] && data[i].item_id == item_id) {
            return i;
        }
    }
    return 0;
}

// 判断当前环境
function checkEnv() {
    const {
        java,
        source
    } = this;

    try {
        java.qread();
        return "轻阅读";
    } catch (e) {}

    try {
        if (typeof java.reLoginView == 'function') {
            return "改版";
        }
        new Packages.io.legato.kazusa.utils.TimeoutCancellationException('');
        return "改版";
    } catch (e) {}
    try {
        java.deviceID();
        return "苹果";
    } catch (e) {}

    if (typeof source.loginUi == 'function') {
        return "安卓";
    }

    return "改版";
}

// 获取番茄token
function getFqToken() {
    const {
        java,
        cookie
    } = this;

    try {
        let cookieValue = String(cookie.getCookie('fanqienovel.com')) || String(java.getCookie('fanqienovel.com'));
        let parts = cookieValue.split(";");
        for (let part of parts) {
            if (part.includes("sessionid")) {
                return part.split("=")[1];
            }
        }
    } catch {}
    return "";
}

// 获取登陆token
function getToken() {
    const {
        java,
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    try {
        for (let h of hostsbk) {
            let cookieValue = String(cookie.getCookie(h)) || String(java.getCookie(h));
            let parts = cookieValue.split(";");
            for (let part of parts) {
                if (part.includes("qttoken")) {
                    return part.split("=")[1];
                }
            }
        }
    } catch {}
    return "";
}

// 移除ck
function removeAllCookies() {
    const {
        java,
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    for (let h of hostsbk) {
        cookie.removeCookie(h);
    }
    cookie.removeCookie('fanqienovel.com');
    java.toast('\n已退出登陆')
}

// 设置ck
function setAllCookies(ck) {
    const {
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    for (let h of hostsbk) {
        cookie.setCookie(h, ck);
    }
}

// 请求封装
function request(url, method, body, req, index) {
    if (method == undefined) method = 'GET';
    if (body == undefined) body = {};
    if (req == undefined) req = true;
    if (index == undefined) index = 0;
    let urla = url;
    if (!url.includes('http')) {
    	urla = this.BaseUrl()+url;
    	}
    const {
        java
    } = this;
    let device = '';
    try {
        device = java.androidId();
    } catch {
        try {
            device = java.deviceID();
        } catch {}
    }
    let qttoken = this.getToken();
    let options = {
        method: method,
        headers: {
            'cookie': `qttoken=${qttoken};deviceId=${device};`,
