// 初始化UI
function initUI() {
  // 设置段评开关
  document.getElementById('duanpingSwitch').checked = settings['段评开关'] != 'false';

  // 设置气泡增大开关
  document.getElementById('bubbleLargeSwitch').checked = settings['气泡增大'] == 'true';

  // 设置段评样式
  document.getElementById('duanpingStyle').value = settings['段评样式'];

  // 设置边框颜色
  const borderColorValue = settings['段评边框颜色'];
  document.getElementById('borderColor').value = borderColorValue === 'transparent' ? '#A7A7A7' : borderColorValue;
  document.getElementById('borderColorText').value = borderColorValue;

  // 设置字体颜色
  const fontColorValue = settings['段评字体颜色'];
  document.getElementById('fontColor').value = fontColorValue === 'transparent' ? '#A7A7A7' : fontColorValue;
  document.getElementById('fontColorText').value = fontColorValue;

