            const regex = new RegExp('id="' + spanId + '"\s*>\s*([^<]*?)\s*<\/span>');
            const match = body.match(regex);
            return match ? match[1].trim() : "";
        };
        const getTextareaValue = (textareaId) => {
            const regex = new RegExp('<textarea[^>]*id="' + textareaId + '"[^>]*>([\\s\\S]*?)<\/textarea>', 'i');
            const match = body.match(regex);
            return match ? match[1].trim() : "";
        };
        const htmlDecode = (str) => {
            if (!str) return str;
            return str.replace(/&amp;/g, '&')
                .replace(/&lt;/g, '<')
                .replace(/&gt;/g, '>')
                .replace(/&quot;/g, '"')
                .replace(/&#039;/g, "'");
        };

        const customStylesValue = getTextareaValue('customStylesValue') || '{}';
        const decodedStyles = htmlDecode(customStylesValue);

        settings = {
            '段评开关': getSpanText('duanpingSwitchValue'),
            '气泡增大': getSpanText('bubbleLargeSwitchValue'),
            '段评样式': getSpanText('duanpingStyleValue') || '0',
            '段评边框颜色': getSpanText('borderColorValue') || '#A7A7A7',
            '段评字体颜色': getSpanText('fontColorValue') || '#A7A7A7',
            '段评填充颜色': getSpanText('fillColorValue') || 'transparent',
            '自定义段评样式': JSON.parse(decodedStyles),
        };
        const settingsText = Object.keys(settings).map(key => `${key}: ${settings[key]}`).join('\n');
        java.longToast("\n" + settingsText);
    } catch (e) {
        settings = {
