<script>
const SOURCES = ${JSON.stringify(config)};
let settings = ${JSON.stringify(data)};
let currentType = '小说';

document.getElementById('tabSource').addEventListener('click', () => {
  document.getElementById('tabSource').classList.add('active');
  document.getElementById('tabBookSource').classList.remove('active');
  document.getElementById('contentSource').classList.add('active');
  document.getElementById('contentBookSource').classList.remove('active');
});

document.getElementById('tabBookSource').addEventListener('click', () => {
  document.getElementById('tabBookSource').classList.add('active');
  document.getElementById('tabSource').classList.remove('active');
  document.getElementById('contentBookSource').classList.add('active');
  document.getElementById('contentSource').classList.remove('active');
});

const subtabs = document.querySelectorAll('.source-subtab');
subtabs.forEach(tab => {
  tab.addEventListener('click', () => {
    subtabs.forEach(t => t.classList.remove('active'));
    tab.classList.add('active');
    currentType = tab.dataset.type;
    renderSourceOptions();
  });
});

function renderSourceOptions() {
  const optionsContainer = document.getElementById('sourceOptions');
  const key = \`搜索\${currentType}\`;
  const sources = SOURCES[key] || [];
  const savedValue = settings[currentType] || '';
  const selectedValues = savedValue === '全部' ? ['全部'] : (savedValue ? savedValue.split(',') : []);

  optionsContainer.innerHTML = '';

  const allOption = document.createElement('div');
  allOption.className = \`source-option all \${selectedValues.includes('全部') ? 'selected' : ''}\`;
  allOption.textContent = '全部';
  allOption.addEventListener('click', () => selectOption('全部'));
  optionsContainer.appendChild(allOption);

  sources.forEach(source => {
    const option = document.createElement('div');
    option.className = \`source-option \${selectedValues.includes(source) ? 'selected' : ''}\`;
    option.textContent = source;
    option.addEventListener('click', () => selectOption(source));
    optionsContainer.appendChild(option);
  });

  updateSelectedInfo();
}

function updateHiddenSettings() {
  const jsonEl = document.getElementById('settingsJson');
  if (jsonEl) {
    jsonEl.textContent = JSON.stringify(settings);
  }

  const typeMap = {
    '小说': 'novelSource',
    '听书': 'audioSource',
    '漫画': 'comicSource',
    '短剧': 'dramaSource',
    '搜索模式': 'searchModeValue',
    '显示图片': 'showImageSwitchValue',
    '完整简介': 'fullDescSwitchValue',
    '同步书架': 'syncBookshelfSwitchValue',
    '同步弹窗': 'syncPopupSwitchValue',
    '网络模式': 'networkModeValue',
    '强制搜索': 'forceSearchSwitchValue',
    '目录显示来源': 'showSourceInTocValue'
  };

  Object.keys(typeMap).forEach(type => {
    const el = document.getElementById(typeMap[type]);
    if (el) {
      el.textContent = settings[type] != undefined ? settings[type] : (type.includes('开关') ? 'false' : '全部');
    }
  });
}

function setupBookSourceSettings() {
  document.getElementById('searchMode').addEventListener('change', (e) => {
    settings['搜索模式'] = e.target.value;
    updateHiddenSettings();
  });

  document.getElementById('showImageSwitch').addEventListener('change', (e) => {
    settings['显示图片'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  document.getElementById('fullDescSwitch').addEventListener('change', (e) => {
    settings['完整简介'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  document.getElementById('syncBookshelfSwitch').addEventListener('change', (e) => {
    settings['同步书架'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();

    const syncPopupSection = document.getElementById('syncPopupSection');
    const syncPopupSwitch = document.getElementById('syncPopupSwitch');
    if (e.target.checked) {
      syncPopupSection.style.display = 'flex';
      if (settings['同步弹窗'] == undefined) {
        settings['同步弹窗'] = 'true';
        syncPopupSwitch.checked = true;
        updateHiddenSettings();
      }
    } else {
      syncPopupSection.style.display = 'none';
    }
  });

  document.getElementById('syncPopupSwitch').addEventListener('change', (e) => {
    settings['同步弹窗'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  document.getElementById('networkMode').addEventListener('change', (e) => {
    settings['网络模式'] = e.target.value;
    updateHiddenSettings();
  });

  document.getElementById('forceSearchSwitch').addEventListener('change', (e) => {
    settings['强制搜索'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  document.getElementById('showSourceInTocSwitch').addEventListener('change', (e) => {
    settings['目录显示来源'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });
}

function initBookSourceSettings() {
  const searchModeEl = document.getElementById('searchMode');
  if (searchModeEl && settings['搜索模式']) {
    searchModeEl.value = settings['搜索模式'];
  }

  const showImageEl = document.getElementById('showImageSwitch');
  if (showImageEl) {
    showImageEl.checked = settings['显示图片'] != 'false';
  }

  const fullDescEl = document.getElementById('fullDescSwitch');
  if (fullDescEl) {
    fullDescEl.checked = settings['完整简介'] != 'false';
  }

  const syncBookshelfEl = document.getElementById('syncBookshelfSwitch');
  if (syncBookshelfEl) {
    syncBookshelfEl.checked = settings['同步书架'] === 'true';
  }

  const syncPopupSection = document.getElementById('syncPopupSection');
  const syncPopupSwitch = document.getElementById('syncPopupSwitch');
  if (syncPopupSwitch) {
    syncPopupSwitch.checked = settings['同步弹窗'] != 'false';
  }
  if (syncPopupSection) {
    syncPopupSection.style.display = (settings['同步书架'] === 'true') ? 'flex' : 'none';
  }

  const networkModeEl = document.getElementById('networkMode');
  if (networkModeEl && settings['网络模式']) {
    networkModeEl.value = settings['网络模式'];
  }

  const forceSearchEl = document.getElementById('forceSearchSwitch');
  if (forceSearchEl) {
    forceSearchEl.checked = settings['强制搜索'] === 'true';
  }

  const showSourceInTocEl = document.getElementById('showSourceInTocSwitch');
  if (showSourceInTocEl) {
    showSourceInTocEl.checked = settings['目录显示来源'] != 'false';
  }
}

function selectOption(value) {
  const key = \`搜索\${currentType}\`;
  const sources = SOURCES[key] || [];

  if (value === '全部') {
    settings[currentType] = '全部';
    updateHiddenSettings();
    renderSourceOptions();
    return;
  }

  let currentValue = settings[currentType] || '';

  if (currentValue === '全部') {
    currentValue = '';
  }

  let values = currentValue ? currentValue.split(',') : [];

  const index = values.indexOf(value);
  if (index > -1) {
    values.splice(index, 1);
  } else {
    values.push(value);
  }

  if (values.length === 0) {
    settings[currentType] = '全部';
  } else {
    settings[currentType] = values.join(',');
  }

  updateHiddenSettings();
  renderSourceOptions();
}

function updateSelectedInfo() {
  const key = \`搜索\${currentType}\`;
  const sources = SOURCES[key] || [];
  const savedValue = settings[currentType] || '';

  if (savedValue === '全部') {
    document.getElementById('selectedCount').textContent = '全部';
  } else {
    const count = savedValue ? savedValue.split(',').length : 0;
    document.getElementById('selectedCount').textContent = count;
  }
}

document.addEventListener('DOMContentLoaded', () => {
  let savedSettings = {};
  try {
    const jsonEl = document.getElementById('settingsJson');
    if (jsonEl) {
      savedSettings = JSON.parse(jsonEl.textContent);
    }
  } catch (e) {
    console.error('读取初始设置失败:', e);
  }

  settings = {
    '小说': savedSettings['小说'] || '全部',
    '听书': savedSettings['听书'] || '全部',
    '漫画': savedSettings['漫画'] || '全部',
    '短剧': savedSettings['短剧'] || '全部',
    '搜索模式': savedSettings['搜索模式'] || '小说',
    '显示图片': savedSettings['显示图片'] || 'true',
    '完整简介': savedSettings['完整简介'] || 'true',
    '同步书架': savedSettings['同步书架'] || 'false',
    '同步弹窗': savedSettings['同步弹窗'] || 'true',
    '网络模式': savedSettings['网络模式'] || '服务器',
    '强制搜索': savedSettings['强制搜索'] || 'false',
    '目录显示来源': savedSettings['目录显示来源'] || 'true'
  };

  initBookSourceSettings();
  setupBookSourceSettings();
  renderSourceOptions();
});
</script>
