//登陆
function login(flag) {
    const token = getToken();
    if (String(token).length > 10) {
        java.longToast(flag ? '\n当前✅️已登录，请🚫退出登录后重新登录' : '\n✅️已登录');
        return true;
    }
    if (flag == undefined) {
        result = JSON.parse(source.getLoginInfo())
    } else {
        source.putLoginInfo(JSON.stringify(result));
        java.longToast("\n\n💞正在登录中...")
    }
    let email = result.邮箱;
    let pwd = result.密码;

    if (!email || !pwd) {
        java.longToast('\n请先输入账号密码！');
        return false;
    }
    if (!email.includes('@')) {
        java.longToast('\n请输入正确的邮箱格式！');
        return false;
    }

    //source.putLoginInfo(result);
    try {
        let options = {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                register_email: email,
                password: pwd
            })
        };
        let url = `${BaseUrl()}/login_api,${JSON.stringify(options)}`
        let data = java.ajax(url)
        const response = JSON.parse(data);
        if (response.code == 0) {
            setAllCookies(`qttoken=${response.key}`);
            java.longToast("\n✅️登录成功");
            return true;
        } else {
            let msg = response.msg;
            if (msg.includes('多次登录失败')) {
                java.longToast('\n💔多次登录失败，请检查账号密码，切换线路后重试或等2小时后重试！');
            } else {
                java.longToast('\n💔' + (msg || "登录失败，请重试！"));
            }
            return false;
        }
    } catch (error) {
        java.longToast('\n💔登录失败，服务器错误，请更换线路后重试！\n' + error);
        return false;
    }
}

