function formatDate(timestamp) {
    const date = new Date(timestamp * 1000);
    return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
}

function isVips(res) {
    const vipEndTime = res.vip_end_time;
    const isVipValue = res.is_vip;

    let vipType;
    if (isVipValue == 0) {
        return '普通用户';
    } else if (isVipValue == 1) {
        vipType = 'VIP';
    } else {
        vipType = 'SVIP';
    }

    if (!vipEndTime || vipEndTime == 0) {
        return `${vipType} (已过期)`;
    }

    const currentTime = Math.floor(Date.now() / 1000);
    const remainingDays = Math.ceil((vipEndTime - currentTime) / (24 * 60 * 60));

    if (currentTime > vipEndTime) {
        return `${vipType} (已过期)`;
    }

    if (remainingDays <= 7) {
        return `${vipType} 剩余${remainingDays}天`;
    }

    if (vipEndTime >= 1912946812) {
        return `${vipType} (永久)`;
    }

    return `${vipType}(${formatDate(vipEndTime)})`;
}

