function getSecretKey() {
    const {
        java,
        source
    } = this;
    try {
        let apiKey = "";
        const headerValue = source.getLoginHeader();
        if (headerValue && String(headerValue).length >= 10) {
            apiKey = String(headerValue);
        }

        if (!apiKey || apiKey.length < 10) {
            java.toast("❌ 未登录，请先登录");
            return "";
        }
        return java.base64Encode(apiKey);
    } catch (e) {
        java.toast("❌ 获取密钥失败");
        return "";
    }
}

function getSortKey() {
    let {
        java
    } = this;
    const sortKey = java.get("sortkey") || '';
    if (!sortKey) {
        java.toast("请先设置排序参数");
    }
    return sortKey;
}

function getBookIdFromUrl(baseUrl) {
    let {
        java,
        source
    } = this;
    let finalUrl;
    let urlMatch = baseUrl.match(/url=([^&]*)/);
    if (urlMatch && urlMatch[1]) {
        finalUrl = java.base64Decode(urlMatch[1]);
    } else {
        let fqurl = JSON.parse(java.base64Decode(baseUrl.split(",")[1]));
        finalUrl = java.base64Decode(fqurl.url);
    }
    let bookIdMatch = finalUrl.match(/book_id=(\d{19})/);
    return bookIdMatch ? bookIdMatch[1] : null;
}

function getBookData(bookId) {
    let {
        java,
        source
    } = this;
    let newUrl = getServerHost.call(this) +'/detail?book_id=' + bookId;
    let response = java.ajax(newUrl);
    let responseData = JSON.parse(response);
    if (Array.isArray(responseData.data)) {
        return responseData.data[0];
    } else {
        return responseData.data;
    }
}

function parseAuthors(authorsData) {
    let {
        java,
        source
    } = this;
    let authors = [];
    try {
        authors = authorsData ? JSON.parse(authorsData) : [];
    } catch (e) {
        authors = authorsData ? authorsData.replace(/[\[\]"]/g, '').split(',') : [];
    }
    return authors.length > 0 ? (authors[0].AuthorName || authors[0] || "") : "";
}

function syncReadingHistory(bookId) {
    let {
        java,
        source
    } = this;
    if (bookId) {
        var sessionid = getSessionId.call(this);
        if (sessionid && sessionid.trim() !== "") {
            var syncUrl = getServerHost.call(this) + "/update_history?book_id=" + bookId + "&sessionid=" + sessionid;
            java.ajax(syncUrl);
        }
    }
}

function buildChapterUrl(x, catalog, device) {
    let { java } = this;
    const isFanqieApp = ['番茄小说', '番茄短剧', '番茄听书', '番茄畅听'].includes(catalog.source);
    const urlToMatch = x.url || catalog.url;
    const bookId = urlToMatch?.match(/book_id=(\d{19})\b/)?.[1] || null;
    const itemId = urlToMatch?.match(/item_id=(\d+)/)?.[1] || null;
    let contentUrlParams = `chapter?cid=${x.cid}&source=${catalog.source}&device=${device}`;

    if (!isFanqieApp) {
        contentUrlParams += `&url=${catalog.url}`;
    } else {
        contentUrlParams += `&book_id=${bookId}&item_id=${itemId}`;
        if (['番茄听书', '番茄畅听'].includes(catalog.source)) {
            const toneId = Number((this.source.getLoginInfoMap())['听书AI音色编号']) || 1;
            contentUrlParams += `&tone_id=${toneId}`;
        }
    }

    if (catalog.source == '企鹅看书' || catalog.source == 'QQ阅读') {
        if (x.url && typeof x.url == 'string') {
            const qqBidMatch = x.url.match(/bookid=(\d+)/);
            const qqCidMatch = x.url.match(/chapterid=(\d+)/);

            if (qqBidMatch && qqCidMatch) {
                if (catalog.source == '企鹅看书') {
                    const filteredBookid = qqBidMatch[1].length > 2 ? qqBidMatch[1].substring(2) : qqBidMatch[1];
                    contentUrlParams += `&bookid=${filteredBookid}&chapterid=${qqCidMatch[1]}`;
                } else if (catalog.source == 'QQ阅读') {
                    contentUrlParams += `&bookid=${qqBidMatch[1]}&chapterid=${qqCidMatch[1]}`;
                }
            }
        }
    }

    let commentPart = '{"type":"qingci"}';

    if (catalog.source == '七猫') {
        const qmBookId = x.url?.match(/book_id=(\d+)/)?.[1] || null;
        const qmChapterId = x.url?.match(/item_id=(\d+)/)?.[1] || null;
        contentUrlParams += `&${x.url}`;
        if (qmBookId && qmChapterId) {
            const qmCommentUrl = `${getServerHost.call(this)}/qm_comment?book_id=${qmBookId}&item_id=${qmChapterId}`;
            commentPart = `{"type":"qingci","js":"book ? result : '${qmCommentUrl}'"}`;
        }
    } else if (catalog.source == '晋江' || catalog.source == '半夏') {
        const novelIdMatch = x.url?.match(/novelId=(\d+)/);
        const chapterIdMatch = x.url?.match(/chapterId=(\d+)/);

        if (novelIdMatch && chapterIdMatch) {
            const novelId = novelIdMatch[1];
            const chapterId = chapterIdMatch[1];
            let jjCommentUrl = `${getServerHost.call(this)}/jj_comment?novelId=${novelId}&chapterId=${chapterId}`;

            if (catalog.source == '半夏') {
                const bjBidMatch = x.url?.match(/bookid=(\d+)/);
                const bjCidMatch = x.url?.match(/chapterid=(\d+)/);
                if (bjBidMatch && bjCidMatch) {
                    jjCommentUrl += `&bookid=${bjBidMatch[1]}&chapterid=${bjCidMatch[1]}`;
                }
            }

            commentPart = `{"type":"qingci","js":"book ? result : '${jjCommentUrl}'"}`;
        }
    } else if (catalog.source == '番茄小说') {
        const fanqieCommentUrl = `${getServerHost.call(this)}/comment?sessionid=${getSessionId.call(this)}&item_id=${itemId}&book_id=${bookId}`;
        commentPart = `{"type":"qingci","js":"book ? result : '${fanqieCommentUrl}'"}`;
    } else if (catalog.source == '云端') {
        const decodedUrl = java.base64Decode(catalog.url);
        const commentUrl = decodedUrl.replace('pt=web', 'pt=3g');
        commentPart = `{"type":"qingci","js":"book ? result : '${commentUrl}'"}`;
    }

    return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},${commentPart}`;
}

function showTabTips(catalog) {
    var tabTips = {
        audio: '听书',
        video: '视频',
        comic: '漫画'
    };
    if (tabTips[catalog.tab]) {
        this.java.toast('当前为' + tabTips[catalog.tab] + '模式');
    }
}

function buildSearchResult(key, sourceParam, host) {
    let {
        java
    } = this;
    if (key && key.length == 19 && !Number.isNaN(parseInt(key))) {
        return handleFanqieSearch.call(this, key, host);
    } else {
        return host + '/search?login=search&key={{key}}&page={{page}}' + sourceParam;
    }
}

function handleFanqieSearch(key, host) {
    let {
        java
    } = this;
    var u = host + `/detail?book_id=${key}`;
    var kdy = java.base64Encode(u);
    var response = JSON.parse(java.ajax(u));
    var nam = response.data.book_name || (response.data[0] && response.data[0].book_name) || '未知';
    return host + `/details?url=${kdy}&source=番茄小说&name=${encodeURIComponent(nam)}`;
}

function decode(data) {
    const {
        java
    } = this;
    const encryptedBytes = java.base64DecodeToByteArray(data);
    const crypto = java.createSymmetricCrypto("DES/CBC/PKCS5Padding", "K7bM2nXy", "tQ5v9rS1");
    return crypto.decryptStr(encryptedBytes);
}

