<body>
    <!-- 顶部栏 -->
    <div class="header">
        <div class="header-left">
            <span class="header-title" id="headerTitle">评论</span>
        </div>
        <div class="sort-buttons" id="sortButtons">
            <button class="comment-btn" id="commentBtn" onclick="openCommentModal()" style="display:none;">
                <i class="fas fa-pen"></i> 去评论
            </button>
            <button class="sort-btn active" id="sortByHot" onclick="sortComments('hot')">
                <i class="fas fa-fire"></i> 最热
            </button>
            <button class="sort-btn" id="sortByTime" onclick="sortComments('time')">
                <i class="fas fa-clock"></i> 最新
            </button>

            <button class="theme-toggle" id="themeToggle" onclick="toggleTheme()">
                <i class="fas fa-moon" id="themeIcon"></i>
            </button>
        </div>
    </div>

    <!-- 主容器 -->
    <div class="main-container">
        <!-- 段落内容 -->
        <div class="paragraph-quote hidden" id="paragraphQuote"></div>

        <!-- 热门评论区域（仅七猫） -->
        <div class="hot-section hidden" id="hotSection">
            <div class="section-header">
                <i class="fas fa-fire"></i>
                <span class="section-title">热门评论</span>
                <span class="section-count" id="hotCount"></span>
            </div>
            <div class="comment-list" id="hotCommentList"></div>
        </div>

        <!-- 更多评论标题（仅七猫） -->
        <div class="hot-section hidden" id="moreSection">
            <div class="section-header">
                <i class="fas fa-clock" style="color: #07c160;"></i>
                <span class="section-title">更多评论</span>
                <span class="section-count" id="moreCount"></span>
            </div>
        </div>

        <!-- 评论列表 -->
        <div style="margin: 0 12px;">
            <div class="comment-list" id="commentList"></div>
        </div>

        <!-- 加载状态 -->
        <div class="loading" id="loading">
            <div class="loading-spinner"></div>
            <span>加载中...</span>
        </div>

        <!-- 空状态 -->
        <div class="empty hidden" id="empty">
            <i class="fas fa-comment-slash"></i>
            <div class="empty-title">暂无评论</div>
            <div class="empty-desc">快来发表第一条评论吧</div>
        </div>

        <!-- 没有更多 -->
        <div class="no-more hidden" id="noMore">— 没有更多评论了 —</div>
    </div>

    <!-- 底部输入栏（仅番茄显示） -->
    <div class="bottom-bar hidden" id="bottomBar">
        <div class="input-wrapper" onclick="openCommentModal()">
            <span>趣评千万条，你也来...</span>
        </div>
        <div class="bottom-actions">
            <i class="far fa-smile bottom-action-btn" onclick="openCommentModal()"></i>
        </div>
    </div>

    <!-- 评论弹窗 -->
    <div class="modal-overlay" id="commentModal" onclick="closeCommentModal(event)">
        <div class="modal-content" onclick="event.stopPropagation()">
            <div class="modal-header">
                <span class="modal-title">发表评论</span>
                <i class="fas fa-times modal-close" onclick="closeCommentModal()"></i>
            </div>
            <div class="modal-textarea-wrapper">
                <textarea class="modal-textarea" id="commentTextarea" placeholder="写下你的想法..." maxlength="500"></textarea>
                <button type="button" class="emoji-toggle-btn" id="emojiToggleBtn" onclick="toggleEmojiPanel(event)">
                    <i class="far fa-smile"></i>
                </button>
                <div class="emoji-panel" id="emojiPanel">
                    <div class="emoji-grid" id="emojiGrid"></div>
                </div>
            </div>
            <div class="modal-footer">
                <span class="char-count" id="charCount">0/500</span>
                <button class="submit-btn" id="submitBtn" onclick="submitComment()">发表</button>
            </div>
        </div>
    </div>

    <!-- 图片预览 -->
    <div class="image-preview" id="imagePreview" onclick="closeImagePreview()">
        <i class="fas fa-times image-preview-close"></i>
        <img id="previewImage" src="" alt="">
    </div>

    <!-- Toast -->
    <div class="toast" id="toast"></div>

    <script>
