@js:
function getMaxPage(arr){
  return Array.from(arr).reduce((max, cur) => {
    const n = +String(cur) || 0;
    return Math.max(max, n)
  }, 1)
};

let chapters = [];
let url = baseUrl;
if(/fiction/.test(baseUrl)){
	 let id = java.get("xchinaID");
	 if(id == "998"){ //漫画小说是图片类型
	 	  book.type = 64;
	 	}else{
	   book.type = 8;
	 }
  let list = java.getElements("@@.chapter-container a");
  let size = list.size();
  if(size == 0){
    chapters.push({
	 	  	 title: java.getString("@@.title@text"),
	 	  	 url
	 	  })
  }else{
    for (let i = 0; i < size; i++) {
      let a = list.get(i);
      chapters.push({
        title: a.text(),
        url:   a.attr('href')
      });
    }
  }
}else if(/photo/.test(baseUrl)){
	 book.type = 64;
	 let pages = java.getStringList("@css:.pager a@text");
	 let max = getMaxPage(pages);
	 if(max == 1) {
	 	  chapters.push({
	 	  	 title: book.name,
	 	  	 url
	 	  })
	 	}else{
	 		chapters.push({
	 		  title: "第1页",
	 		  url
	 		})
	 		for(let i = 2; i <= max; i++){
      chapters.push({
        title: `第${i}页`,
        url: url.replace(".html", `/${i}.html`)
      })
    }
	 }

}else if(/video/.test(baseUrl)){
	 book.type = 4;
	 chapters.push({
	 	  title: book.name,
	 	  url
	 })
}

chapters;

