loginUrl:
//理论上加上这个函数可以支持更多版本
function login() {}

function replace() {
    try {
        let currentVar = { data: { replace: true, host: "" } };
        const varString = source.getVariable();

        if (varString) {
            try {
                currentVar = JSON.parse(varString);
            } catch (e) {
                java.log("解析源变量失败: " + e);
            }
        }

        if (!currentVar.data) {
            currentVar.data = {};
        }
        if (currentVar.data.replace === undefined) {
            currentVar.data.replace = true;
        } else {
            currentVar.data.replace = !currentVar.data.replace;
        }
        currentVar.data.host = "";
        const jsonStr = JSON.stringify(currentVar, null, "\t");
        source.setVariable(jsonStr);
        const status = currentVar.data.replace ? "✅ 已启用" : "❌ 已禁用";
        java.toast(`简繁替换 ${status}`);

        //java.log("当前替换状态: " + currentVar.data.replace);

    } catch (e) {
        java.toast("切换失败: " + e.message);
        java.log("replace函数错误: " + e + "\n" + e.stack);
    }
}

function X() {
	   let loginInfo = source.getLoginInfoMap();
	   if(!loginInfo) loginInfo = {};
	   let host = loginInfo["这里填入更新后的网址"]||"";
	   let Variable;
	   try {
	         Variable = JSON.parse(source.getVariable()).data.replace;
	   } catch (e) {
	   	      Variable = true;
	   }
	   let variable = JSON.stringify({
	   	data: {
	   		  replace: Variable,
	   		  host: host
	   	 	},
	   });
	   java.log(host);
	   	source.getVariable(variable);
	   	java.toast("源站已更新：" + host);
	}

