ruleContent.content:
@js:
var text = String(result || '').split('\\/').join('/');
var reg = /(?:https?:)?\/\/[^"'\s]+?\.(?:jpg|jpeg|png|webp)(?:\?[^"'\s]*)?/ig;
var urls = [];
var seen = {};
var m;
while ((m = reg.exec(text)) != null) {
  var url = m[0];
  if (url.indexOf('//') == 0) url = 'https:' + url;
  if (!seen[url]) {
    seen[url] = true;
    urls.push(url);
  }
}
result = urls.map(function(url) {
  return '<img src="' + url + '">';
}).join('');

