@js:
let list = [];
const style = (size) => ({
    "layout_flexGrow": 1,
    "layout_flexBasisPercent": size
});
const web = (url) => url ? url + ',{"webView":true}' : '';
const push = (title, url, size) => list.push({
    "title": title,
    "url": web(url),
    "style": style(size)
});
const heading = (title) => list.push({
    "title": title,
    "url": "",
    "style": style(1)
});
const page = "{{page}}";
const withPage = (path) => path + (path.indexOf('?') >= 0 ? '&' : '?') + `page=${page}`;

heading("入口");
push("最新", `?page=${page}`, 0.3);
push("最多播放", withPage("rankings/playback"), 0.3);
push("TOP250", withPage("rankings/top"), 0.3);
push("FANZA大奖", withPage("rankings/fanza_award"), 0.3);

heading("排行·有码");
[
    ["日榜", "daily"],
    ["周榜", "weekly"],
    ["月榜", "monthly"]
].forEach(([title, period]) => push(title, `rankings/movies?p=${period}&t=censored&page=${page}`, 0.3));

heading("排行·分类");
[
    ["无码日榜", "daily", "uncensored"],
    ["欧美日榜", "daily", "western"],
    ["FC2日榜", "daily", "fc2"],
    ["无码周榜", "weekly", "uncensored"],
    ["欧美周榜", "weekly", "western"],
    ["FC2周榜", "weekly", "fc2"],
    ["无码月榜", "monthly", "uncensored"],
    ["欧美月榜", "monthly", "western"],
    ["FC2月榜", "monthly", "fc2"]
].forEach(([title, period, type]) => push(title, `rankings/movies?p=${period}&t=${type}&page=${page}`, 0.3));

heading("一级分类");
const categories = [
    ["全部", ""],
    ["有码", "censored"],
    ["无码", "uncensored"],
    ["欧美", "western"],
    ["FC2", "fc2"],
    ["动漫", "anime"]
];
categories.forEach(([title, path]) => push(title, path ? withPage(path) : `?page=${page}`, 0.3));

const filters = [
    ["全部", "vft=0"],
