    ["中字可播放", "vft=5&vst=3"],
    ["含磁链", "vft=1"],
    ["含字幕", "vft=2"],
    ["含短评", "vft=3"]
];
categories.filter(([title, path]) => path).forEach(([categoryTitle, path]) => {
    heading(`${categoryTitle}·二级筛选`);
    filters.forEach(([filterTitle, query]) => push(filterTitle, `${path}?${query}&page=${page}`, 0.23));
});

heading("热门 Tag");
[
    ["LUXU", "video_codes/LUXU"],
    ["VR", "search?from_recent=1&q=VR"],
    ["肛交", `search?from_recent=1&q=${encodeURIComponent("肛交")}`],
