let doc = org.jsoup.Jsoup.parse(result);
let tags = [];
let items = doc.select('.movie-panel-info .panel-block, .video-meta-panel .panel-block, .panel .panel-block');
for (let i = 0; i < items.size(); i++) {
    let el = items.get(i);
    let label = el.select('strong').text();
    if (/類別|类别|分類|分类|Genre/i.test(label)) {
        let links = el.select('a');
        for (let k = 0; k < links.size(); k++) tags.push(links.get(k).text());
    }
}
tags.join(',');

