@js:
let html = String(result);
let cleanUrl = String(baseUrl || '').replace(/#.*$/, '').replace(/,\{[\s\S]*\}$/, '');
let media = '';
let m = html.match(/<video[\s\S]*?<source[^>]+src=["']([^"']+)/i) || html.match(/<source[^>]+src=["']([^"']+\.(?:m3u8|mp4)[^"']*)/i) || html.match(/data-video-url=["']([^"']+)/i);
if (m) {
    media = m[1].replace(/&amp;/g, '&');
    if (media.startsWith('//')) {
        media = 'https:' + media;
    } else if (media.startsWith('/')) {
        media = source.getKey().replace(/\/$/, '') + media;
    }
}

if (media) {
    try {
        java.startBrowserAwait(media, book.name);
    } catch (err) {
        media;
    }
} else {
    let magnets = [];
    let reg = /(?:data-clipboard-text|href)=["'](magnet:\?xt=[^"']+)/ig;
    let r;
    while ((r = reg.exec(html)) !== null) {
        let u = r[1].replace(/&amp;/g, '&');
        if (magnets.indexOf(u) < 0) magnets.push(u);
    }
    if (magnets.length > 0) {
        magnets.join('\n\n');
    } else {
        try {
            java.startBrowserAwait(cleanUrl || source.getKey(), book.name);
        } catch (err) {
            cleanUrl || '未获取到视频地址';
        }
    }
}
